"use client";
import { useState } from "react";

const BENEFITS = [
    ["Full Business Audit", "We map your entire operation before making a single recommendation."],
    ["Custom AI Roadmap", "Step-by-step deployment plan delivered within 48h of the call."],
    ["14-Day Priority Access", "Direct line to our team for questions and quick-turn deliverables."],
];

const SERVICES_OPT = [
    "1-1 Strategy Consulting",
    "Custom AI Website",
    "Custom Dashboard",
    "PDF to Video",
    "Custom Ads",
    "Multiple Services",
];
const REVENUE_OPT = ["Under $5k/mo", "$5k–$25k/mo", "$25k–$100k/mo", "$100k+/mo"];

export default function LeadCaptureForm() {
    const [form, setForm] = useState({
        name: "",
        email: "",
        company: "",
        service: "",
        revenue: "",
        situation: "",
    });
    const [sent, setSent] = useState(false);
    const [loading, setLoading] = useState(false);

    const update = (k: string) => (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) =>
        setForm((f) => ({ ...f, [k]: e.target.value }));

    async function handleSubmit(e: React.FormEvent) {
        e.preventDefault();
        if (!form.name || !form.email) return;
        setLoading(true);
        try {
            await fetch("/api/lead", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(form),
            });
        } catch {
            /* continue */
        }
        setTimeout(() => {
            setLoading(false);
            setSent(true);
        }, 900);
    }

    return (
        <section id="consulting" className="py-28 px-6 lg:px-10 bg-[#050505] relative overflow-hidden">
            {/* Ambient glow */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[400px] bg-brand-cyan/[0.05] rounded-full blur-[80px] pointer-events-none" />

            <div className="max-w-[1100px] mx-auto grid lg:grid-cols-2 gap-16 items-start relative z-10">
                {/* Left: Sales copy */}
                <div>
                    <div className="badge-live mb-6">8 Spots Available This Month</div>

                    <h2 className="text-3xl sm:text-4xl lg:text-5xl font-bold tracking-tight text-white leading-[1.15] mb-5">
                        Book Your<br />
                        <span className="text-brand-cyan">Strategy Session</span>
                    </h2>

                    <p className="text-zinc-500 text-sm leading-relaxed mb-8">
                        90 minutes. Zero pitch. Walk away with a custom AI roadmap, your top 3 automation wins, and a revenue projection built for your business specifically.
                    </p>

                    {BENEFITS.map(([title, desc]) => (
                        <div key={title} className="flex gap-3 items-start mb-5">
                            <div className="w-[22px] h-[22px] rounded-md bg-brand-cyan/[0.1] flex items-center justify-center shrink-0 mt-0.5">
                                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#06b6d4" strokeWidth="2.5">
                                    <polyline points="20 6 9 17 4 12" />
                                </svg>
                            </div>
                            <div>
                                <div className="text-[13px] font-semibold text-white mb-1">{title}</div>
                                <div className="text-xs text-zinc-500 leading-relaxed">{desc}</div>
                            </div>
                        </div>
                    ))}

                    {/* Price card */}
                    <div className="mt-6 p-5 bg-brand-cyan/[0.04] border border-brand-cyan/[0.15] rounded-xl">
                        <div className="text-[11px] text-zinc-600 uppercase tracking-[0.1em] mb-1.5">Session Investment</div>
                        <div className="text-3xl font-extrabold text-white">
                            $997{" "}
                            <span className="text-sm font-normal text-zinc-500">one-time</span>
                        </div>
                        <div className="text-xs text-zinc-500 mt-1">100% credited toward any build project</div>
                    </div>
                </div>

                {/* Right: Live form */}
                <div className="bg-[#09090b]/90 border border-brand-cyan/[0.15] rounded-2xl p-8 backdrop-blur-xl">
                    {sent ? (
                        <div className="text-center py-12">
                            <div className="w-[60px] h-[60px] rounded-full bg-brand-cyan/[0.1] flex items-center justify-center mx-auto mb-5">
                                <svg width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="#06b6d4" strokeWidth="2">
                                    <polyline points="20 6 9 17 4 12" />
                                </svg>
                            </div>
                            <h3 className="text-white text-xl font-bold mb-3">Request Received ✓</h3>
                            <p className="text-zinc-500 text-sm leading-relaxed">
                                We review every application personally. Expect a reply within 4 hours during business hours.
                            </p>
                        </div>
                    ) : (
                        <>
                            <h3 className="text-white text-xl font-bold mb-1.5">Initialize Your Session</h3>
                            <p className="text-zinc-600 text-xs mb-6">We read every form. No auto-responders. No bots.</p>

                            <form onSubmit={handleSubmit} className="flex flex-col gap-3">
                                <div className="grid grid-cols-2 gap-3">
                                    <input
                                        className="glass-input"
                                        placeholder="Full Name *"
                                        value={form.name}
                                        onChange={update("name")}
                                        required
                                        aria-label="Full name"
                                    />
                                    <input
                                        className="glass-input"
                                        type="email"
                                        placeholder="Work Email *"
                                        value={form.email}
                                        onChange={update("email")}
                                        required
                                        aria-label="Work email"
                                    />
                                </div>

                                <input
                                    className="glass-input"
                                    placeholder="Company / Business"
                                    value={form.company}
                                    onChange={update("company")}
                                    aria-label="Company"
                                />

                                <select
                                    className="glass-input appearance-none cursor-pointer"
                                    value={form.service}
                                    onChange={update("service")}
                                    aria-label="Select a service"
                                >
                                    <option value="" className="bg-[#09090b]">What do you need?</option>
                                    {SERVICES_OPT.map((o) => (
                                        <option key={o} className="bg-[#09090b]">{o}</option>
                                    ))}
                                </select>

                                <select
                                    className="glass-input appearance-none cursor-pointer"
                                    value={form.revenue}
                                    onChange={update("revenue")}
                                    aria-label="Revenue range"
                                >
                                    <option value="" className="bg-[#09090b]">Current Monthly Revenue</option>
                                    {REVENUE_OPT.map((o) => (
                                        <option key={o} className="bg-[#09090b]">{o}</option>
                                    ))}
                                </select>

                                <textarea
                                    className="glass-input resize-none"
                                    placeholder="What's your biggest bottleneck right now?"
                                    value={form.situation}
                                    onChange={update("situation")}
                                    rows={3}
                                    aria-label="Describe your situation"
                                />

                                <button
                                    type="submit"
                                    disabled={loading}
                                    className={`btn-primary mt-1 ${loading ? "opacity-70" : ""}`}
                                >
                                    {loading ? "Submitting..." : "Request Session →"}
                                </button>

                                <p className="text-[10px] text-zinc-700 text-center">
                                    Limited to 8 sessions per month. No spam ever.
                                </p>
                            </form>
                        </>
                    )}
                </div>
            </div>
        </section>
    );
}
