"use client";
import { useState } from "react";
import Link from "next/link";

const SERVICES = [
    {
        id: "01",
        title: "AI Consulting 1-1",
        desc: "90-min private strategy session. Walk away with a custom roadmap.",
        href: "/consulting"
    },
    {
        id: "02",
        title: "Custom AI Websites",
        desc: "Next.js sites engineered to convert — shipped in under 10 days.",
        href: "/websites"
    },
    {
        id: "03",
        title: "Custom Dashboards",
        desc: "Live revenue intelligence — KPI tracking and lead scoring.",
        href: "/dashboards"
    },
    {
        id: "04",
        title: "PDF to Video",
        desc: "Transform complex documents into narrated videos instantly.",
        href: "/dashboards"
    },
    {
        id: "05",
        title: "Photo & Video Ads",
        desc: "AI-generated product ads — 10x the speed and 1/5 the cost.",
        href: "/ads"
    },
];

export default function HeroSection() {
    const [active, setActive] = useState(0);

    return (
        <section className="relative pt-32 pb-20 overflow-hidden">
            <div className="max-w-7xl mx-auto px-6">
                <div className="flex flex-col lg:flex-row items-center gap-16">

                    {/* Left: Content */}
                    <div className="flex-1 text-left">
                        <div className="mb-8 flex items-center gap-3">
                            <span className="w-2 h-2 rounded-full bg-cyan-500 animate-pulse" />
                            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-cyan-500/80">AI Strategy Group — Accepting Clients</span>
                        </div>

                        <h1 className="text-6xl md:text-8xl font-black text-white leading-[0.9] tracking-tighter mb-8 uppercase">
                            Bowen Ai<br />
                            <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 via-blue-500 to-indigo-600">Strategy</span><br />
                            Group
                        </h1>

                        <p className="text-lg md:text-xl text-zinc-400 max-w-xl leading-relaxed mb-10">
                            Custom AI websites, dashboards, ads, and strategy — built for founders who want results in days, not months.
                        </p>

                        <div className="flex flex-wrap gap-4 mb-12">
                            <Link href="/consulting" className="px-8 py-4 rounded-xl bg-cyan-500 text-sm font-black text-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-[0_0_30px_rgba(6,182,212,0.4)] hover:scale-105 active:scale-95">
                                Book a Strategy Call →
                            </Link>
                            <Link href="/websites" className="px-8 py-4 rounded-xl bg-white/5 border border-white/10 text-sm font-black text-white uppercase tracking-widest hover:bg-white/10 transition-all">
                                See Our Work
                            </Link>
                        </div>

                        <div className="flex items-center gap-10 text-zinc-500 font-bold text-[10px] uppercase tracking-widest">
                            <div className="flex flex-col">
                                <span className="text-white text-lg font-black tracking-normal">500+</span>
                                projects
                            </div>
                            <div className="h-4 w-px bg-white/10" />
                            <div className="flex flex-col">
                                <span className="text-white text-lg font-black tracking-normal">48h</span>
                                delivery
                            </div>
                            <div className="h-4 w-px bg-white/10" />
                            <div className="flex flex-col">
                                <span className="text-white text-lg font-black tracking-normal">Global</span>
                                clients
                            </div>
                        </div>
                    </div>

                    {/* Right: The CSS Globe (Cyan/Cyber Focus) */}
                    <div className="flex-1 relative w-full aspect-square max-w-lg">
                        <div className="absolute inset-0 flex items-center justify-center">
                            {/* Outer Rings */}
                            <div className="absolute w-[100%] h-[100%] rounded-full border border-cyan-500/10 animate-[spin_20s_linear_infinite]" />
                            <div className="absolute w-[80%] h-[80%] rounded-full border border-cyan-500/5 animate-[spin_15s_linear_infinite_reverse]" />
                            <div className="absolute w-[60%] h-[60%] rounded-full border border-cyan-500/10" />

                            {/* The Sphere */}
                            <div className="relative w-[70%] h-[70%] rounded-full bg-zinc-950 border border-cyan-500/20 shadow-[inset_0_0_50px_rgba(34,211,238,0.15)] overflow-hidden">
                                {/* Visual Continent Blobs */}
                                <div className="absolute top-1/4 left-1/4 w-32 h-20 bg-cyan-500/20 blur-3xl rounded-full" />
                                <div className="absolute top-1/2 right-1/4 w-40 h-28 bg-blue-500/20 blur-3xl rounded-full" />
                                <div className="absolute bottom-1/4 left-1/3 w-24 h-16 bg-cyan-400/20 blur-3xl rounded-full" />

                                {/* Grid Overlay */}
                                <div className="absolute inset-0 opacity-20 bg-[radial-gradient(circle_at_center,rgba(6,182,212,0.1)_1px,transparent_1px)] bg-[size:24px_24px]" />

                                {/* Interactive Points */}
                                <div className="absolute top-[20%] left-[30%] w-1.5 h-1.5 bg-cyan-400 rounded-full shadow-[0_0_10px_rgba(34,211,238,1)] animate-pulse" />
                                <div className="absolute top-[50%] right-[40%] w-1.5 h-1.5 bg-indigo-500 rounded-full shadow-[0_0_10px_rgba(99,102,241,1)]" />
                                <div className="absolute bottom-[30%] left-[45%] w-1 h-1 bg-white rounded-full opacity-50" />
                            </div>

                            {/* Orbital Ring */}
                            <div className="absolute w-[85%] h-[85%] border-t border-cyan-500/40 rounded-full -rotate-[60deg] opacity-40" />
                        </div>
                    </div>
                </div>

                {/* Lower: Service Strip (Tied to multi-page) */}
                <div className="mt-32">
                    <p className="text-[10px] font-black uppercase tracking-[0.4em] text-zinc-500 mb-8">What We Build</p>
                    <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-4">
                        {SERVICES.map((service, idx) => (
                            <Link
                                key={service.id}
                                href={service.href}
                                onMouseEnter={() => setActive(idx)}
                                className={`group p-6 rounded-2xl border transition-all duration-500 ${active === idx ? 'bg-cyan-500/5 border-cyan-500/50 shadow-[0_10px_30px_-10px_rgba(6,182,212,0.2)]' : 'bg-white/[0.02] border-white/5 hover:border-white/10'}`}
                            >
                                <span className={`block text-[10px] font-black mb-4 transition-colors ${active === idx ? 'text-cyan-400' : 'text-zinc-600'}`}>{service.id}</span>
                                <h3 className={`text-sm font-bold mb-2 transition-colors ${active === idx ? 'text-white' : 'text-zinc-400 group-hover:text-white'}`}>{service.title}</h3>
                                <p className="text-xs text-zinc-500 leading-relaxed">{service.desc}</p>
                            </Link>
                        ))}
                    </div>
                </div>
            </div>
        </section>
    );
}
